<?php
 declare(strict_types=1); namespace tapmeppe\composer\blueprint; class Route { protected bool $public = false; function __construct( protected Database $database, protected Object $mode, protected RequestAPI $request, protected ResponseAPI $response, private string $directory, ) { if (!$this->public) { $permissions = $this->request->getPermissions(); if (!$permissions) $this->response->reject(Reason::authentication, [], 401); elseif (is_array($permissions) && !in_array($this->request->getRoute(), $permissions)) $this->response->reject(Reason::authorisation, [], 403); elseif (is_string($permissions) && !preg_match("@^$permissions$@", $this->request->getRouteAsString())) $this->response->reject(Reason::authorisation, [], 403); } } function prepare(): void {} function delete(object $payload): void { $this->replyNotImplemented(); } function get(object $payload): void { $this->replyNotImplemented(); } function post(object $payload): void { $this->replyNotImplemented(); } function put(object $payload): void { $this->replyNotImplemented(); } final function replyNotImplemented(): void { $this->response->reject( Reason::implementation, [ 'The request method "' . $_SERVER['REQUEST_METHOD'] . '" is not implemented.', 'Route: ' . Resources::getPathRelative(Resources::getPathOptimised(__FILE__), $this->directory), ], ); } } 